// Work slower than the timeout returns 504 and does not hang.
func TestTimesOutWith504(t *testing.T) {
	h := TimeoutHandler(20*time.Millisecond, 500*time.Millisecond)
	rec := httptest.NewRecorder()

	done := make(chan struct{})
	go func() {
		h.ServeHTTP(rec, httptest.NewRequest(http.MethodGet, "/work", nil))
		close(done)
	}()

	select {
	case <-done:
	case <-time.After(2 * time.Second):
		t.Fatal("handler hung past the deadline")
	}
	if rec.Code != http.StatusGatewayTimeout {
		t.Fatalf("want 504, got %d", rec.Code)
